// Array: {10, 9, 2, 5, 3, 7, 101, 18}
// Find the length of the LONGEST strictly increasing subsequence
// (recall Longest Common Subsequence: elements don't need to be contiguous, order must be preserved)

// For every earlier index j < i where arr[j] < arr[i]:
// arr[i] could EXTEND that subsequence, giving length dp[j] + 1
// dp[i] takes the BEST such extension found across all valid j

// dp[i] = max( dp[j] + 1 )  for every j < i where arr[j] < arr[i]
// dp[i] = 1  if no such j exists (arr[i] starts its own subsequence)

#include <iostream>
#include <vector>

using namespace std;

int lengthOfLIS(vector<int> &arr)
{
    int n = arr.size();
    vector<int> dp(n, 1); // every element is at least a subsequence of length 1 by itself

    for (int i = 0; i < n; i++)
    {
        for (int j = 0; j < i; j++)
        {
            if (arr[j] < arr[i])
            {
                dp[i] = max(dp[i], dp[j] + 1);
            }
        }
    }

    int best = 0;
    for (int i = 0; i < n; i++)
    {
        best = max(best, dp[i]);
    }

    return best;
}

int main()
{
    vector<int> arr = {10, 9, 2, 5, 3, 7, 101, 18};

    cout << lengthOfLIS(arr) << endl;

    return 0;
}

