#include <vector>
#include <algorithm>

using namespace std;

int findNumberOfLIS(vector<int>& nums)
{
    int n = nums.size();
    vector<int> dp(n, 1), count(n, 1);

    for (int i = 0; i < n; i++)
        for (int j = 0; j < i; j++)
            if (nums[j] < nums[i])
            {
                if (dp[j] + 1 > dp[i])
                {
                    dp[i] = dp[j] + 1;
                    count[i] = count[j];
                }
                else if (dp[j] + 1 == dp[i])
                {
                    count[i] += count[j];
                }
            }

    int maxLen = 0;
    for (int val : dp) maxLen = max(maxLen, val);

    int result = 0;
    for (int i = 0; i < n; i++)
        if (dp[i] == maxLen) result += count[i];

    return result;
}

int main()
{
    vector<int> nums = {1, 3, 5, 4, 7};
    cout << findNumberOfLIS(nums);

    return 0;
}

